SELECT mr.id, mr.medical_order_id, mr.pet_id, mr.doctor_name, mr.chief_complaint, mr.physical_exam, mr.diagnosis, mr.medical_advice, mr.medication, mr.remark, mr.visit_time, mr.create_time, pet.name AS pet_name, u.username AS owner_name, dept.name AS department_name FROM medical_record mr LEFT JOIN pet ON mr.pet_id = pet.id LEFT JOIN user u ON pet.user_id = u.id LEFT JOIN medical_order mo ON mr.medical_order_id = mo.id LEFT JOIN department dept ON mo.department_id = dept.id
AND (pet.name LIKE CONCAT('%',#{keyword},'%') OR u.username LIKE CONCAT('%',#{keyword},'%') OR mr.doctor_name LIKE CONCAT('%',#{keyword},'%') OR mr.diagnosis LIKE CONCAT('%',#{keyword},'%'))
ORDER BY mr.create_time DESC LIMIT #{offset}, #{pageSize}

mapper.update:
UPDATE medical_record
medical_order_id = #{medicalOrderId}, pet_id = #{petId}, doctor_name = #{doctorName}, chief_complaint = #{chiefComplaint}, physical_exam = #{physicalExam}, diagnosis = #{diagnosis}, medical_advice = #{medicalAdvice}, medication = #{medication}, remark = #{remark}, visit_time = #{visitTime},
WHERE id = #{id}
